mapper.insert:
INSERT INTO IMPORT_TAX_PAYMENT_LOG (
      ACTION_TYPE
    , ACTION_DATE
    , WORKER_ID

    -- 원본 데이터 매핑
    , PAY_ID
    , MEM_ID
    , PAY_STATUS
    , TOTAL_AMOUNT
    , TAX_BASE
    , DUTY_AMT
    , VAT_AMT
    , ISSUE_DATE
    , DUE_DATE
    , PAID_DATE
    , BANK_NAME
    , VIRTUAL_ACCT
    , PAYER_NAME
    , BIZ_REG_NO
    , DEL_YN
    , REMARKS
    , OFFICER_ID
    , IMPORT_ID
) VALUES (
      #{actionType}
    , SYSDATE
    , #{workerId}

    , #{payId}
    , #{memId}
    , #{payStatus}
    , #{totalAmount}
    , #{taxBase}
    , #{dutyAmt}
    , #{vatAmt}
    , #{issueDate}
    , #{dueDate}
    , #{paidDate}
    , #{bankName}
    , #{virtualAcct}
    , #{payerName}
    , #{bizRegNo}
    , #{delYn}
    , #{remarks}
    , #{officerId}
    , #{importId}
)
